export const SUPPORTED_CURRENCIES = ["USD", "AED"] as const;
export type SupportedCurrency = (typeof SUPPORTED_CURRENCIES)[number];
export const DEFAULT_CURRENCY: SupportedCurrency = "AED";

export const CURRENCY_META: Record<
  SupportedCurrency,
  { symbol: string; locale: string; flag: string; rateFromUsd: number }
> = {
  USD: { symbol: "$", locale: "en-US", flag: "🇺🇸", rateFromUsd: 1 },
  AED: { symbol: "AED", locale: "en-US", flag: "🇦🇪", rateFromUsd: 3.6725 },
};

/** Convert minor units (cents/fils) from USD to target currency */
export function convertMinorUnits(
  amount: number,
  toCurrency: SupportedCurrency,
): number {
  if (toCurrency === "USD") return amount;
  return Math.round(amount * CURRENCY_META[toCurrency].rateFromUsd);
}

