import { getApi } from "@/shared/api/api";
import { API_ROUTES } from "@/shared/config/api-routes";
import { ENV } from "@/shared/config/env";
import type {
  Address,
  Profile,
  UpdateProfileDto,
  UpdateProfilePhotoDto,
  UpdateSettingsDto,
  UpsertAddressDto,
  UserSettings,
} from "../model/types";

export async function getProfile(): Promise<Profile> {
  const api = await getApi({ auth: true });

  const response = await api.get<Profile>(API_ROUTES.PROFILE.GET);

  return response.data;
}

export async function getProfileWithToken(
  accessToken: string,
): Promise<Profile> {
  const api = await getApi();

  const response = await api.get<Profile>(API_ROUTES.PROFILE.GET, {
    baseURL: ENV.NEXT_PUBLIC_APP_API_URL,
    headers: {
      Authorization: `Bearer ${accessToken}`,
    },
  });

  return response.data;
}

export async function getAddresses(): Promise<Address[]> {
  const api = await getApi({ auth: true });

  const response = await api.get<Address[]>(API_ROUTES.PROFILE.ADDRESS);

  return response.data;
}

export async function updateProfile(data: UpdateProfileDto): Promise<Profile> {
  const api = await getApi();

  const response = await api.patch<Profile>(API_ROUTES.PROFILE.UPDATE, data);

  return response.data;
}

export async function updateProfilePhoto(
  data: UpdateProfilePhotoDto,
): Promise<Profile> {
  const api = await getApi();

  const response = await api.patch<Profile>(
    API_ROUTES.PROFILE.UPDATE_PHOTO,
    data,
  );

  return response.data;
}

export async function upsertAddress(data: UpsertAddressDto): Promise<Address> {
  const api = await getApi();

  const response = await api.patch<Address>(API_ROUTES.PROFILE.ADDRESS, data);

  return response.data;
}

export async function deleteAddress(id: string): Promise<void> {
  const api = await getApi();

  await api.delete(`${API_ROUTES.PROFILE.ADDRESS}/${id}`);
}

export async function getUserSettings(): Promise<UserSettings> {
  const api = await getApi();

  const response = await api.get<UserSettings>(API_ROUTES.PROFILE.SETTINGS);

  return response.data;
}

export async function updateUserSettings(
  data: UpdateSettingsDto,
): Promise<{ success: boolean }> {
  const api = await getApi();

  const response = await api.patch<{ success: boolean }>(
    API_ROUTES.PROFILE.SETTINGS,
    data,
  );

  return response.data;
}

