"use client";

import { UserSetting, useUserSettings } from "@/entities/profile";
import {
  DEFAULT_CURRENCY,
  type SupportedCurrency,
} from "@/shared/config/currency-config";
import { useCurrencyStore } from "@/shared/model/currency-store";
import type { FC, PropsWithChildren } from "react";
import { useEffect } from "react";

export const CurrencySyncProvider: FC<PropsWithChildren> = ({ children }) => {
  const { data: settings } = useUserSettings();

  useEffect(() => {
    if (!settings) return;

    const currency: SupportedCurrency =
      settings[UserSetting.Currency] ?? DEFAULT_CURRENCY;

    useCurrencyStore.getState().setCurrency(currency);
  }, [settings]);

  return <>{children}</>;
};

